
    const CONFIG = {
      companyName: 'Ziran Logistica e transporte',
      subtitle: 'Painel de Desempenho',
      sheetId: '1rJD9B5YP98mrzYI2MTv2ouPZjPnh9bc2C3eHeywg2ug',
      logoDataUrl: 'data:image/jpeg;base64,',
      monthNames: ['Janeiro','Fevereiro','Março','Abril','Maio','Junho','Julho','Agosto','Setembro','Outubro','Novembro','Dezembro'],
      metaSheetName: 'meta'
    };

    const state = {
      metaRows: [],
      monthData: {},
      charts: {},
      selectedMonth: null,
      selectedDriver: 'TODOS',
      currentPage: 'executive',
      metaMap: new Map()
    };

    document.getElementById('logoImg').src = CONFIG.logoDataUrl;

    function parseNumber(value) {
      if (value == null || value === '') return 0;
      if (typeof value === 'number') return Number.isFinite(value) ? value : 0;
      const str = String(value).trim();
      if (!str) return 0;
      const normalized = str.includes(',') ? str.replace(/\./g, '').replace(',', '.') : str;
      const num = Number(normalized);
      return Number.isFinite(num) ? num : 0;
    }
    function formatNumber(value, digits = 1) { return Number(value || 0).toLocaleString('pt-BR', { minimumFractionDigits: digits, maximumFractionDigits: digits }); }
    function formatInt(value) { return Number(value || 0).toLocaleString('pt-BR', { maximumFractionDigits: 0 }); }
    function gradeFromScore(score) { if (score >= 90) return 'A'; if (score >= 80) return 'B'; if (score >= 70) return 'C'; if (score >= 60) return 'D'; return 'E'; }
    function gradeClass(letter) { return `grade-${String(letter||'e').toLowerCase()}`; }
    function pillColor(letter) { return ({ A:'#16a34a', B:'#65a30d', C:'#ca8a04', D:'#ea580c', E:'#dc2626' })[letter] || '#64748b'; }
    function clamp(value, min = 0, max = 100) { return Math.max(min, Math.min(max, Number.isFinite(value) ? value : 0)); }
    function firstNumber(row, keys) {
      for (const key of keys) {
        if (row[key] != null && row[key] !== '') return parseNumber(row[key]);
      }
      return 0;
    }
    function computeConsumptionScore(consumo, meta) {
      if (!(meta > 0)) return null;
      return clamp((consumo / meta) * 100);
    }
    function computeIdleScore(marchaLenta) {
      if (!(marchaLenta >= 0)) return null;
      if (marchaLenta <= 20) return 100;
      return clamp((20 / marchaLenta) * 100);
    }
    function computeInertiaScore(inercia) {
      if (!(inercia >= 0)) return null;
      return clamp(inercia);
    }
    function computeSpeedScore(excessoVelocidade) {
      if (!(excessoVelocidade >= 0)) return null;
      return clamp(100 - (excessoVelocidade * 5));
    }
    function computeDriverNote({ consumo, meta, supportUsage, marchaLenta, inercia, excessoVelocidade }) {
      const components = [
        computeConsumptionScore(consumo, meta),
        clamp(supportUsage),
        computeIdleScore(marchaLenta),
        computeInertiaScore(inercia),
        computeSpeedScore(excessoVelocidade)
      ].filter(v => v != null);
      return components.length ? avg(components.map(v => ({ value: v })), 'value') : 0;
    }

    function loadSheetJSONP(sheetName) {
      return new Promise((resolve, reject) => {
        const callbackName = `gviz_callback_${Date.now()}_${Math.floor(Math.random() * 100000)}`;
        const script = document.createElement('script');
        const timeout = setTimeout(() => { cleanup(); reject(new Error(`Tempo esgotado ao carregar ${sheetName}`)); }, 15000);
        function cleanup() { clearTimeout(timeout); delete window[callbackName]; if (script.parentNode) script.parentNode.removeChild(script); }
        window[callbackName] = (response) => {
          try {
            cleanup();
            if (!response || !response.table) return reject(new Error(`Resposta inválida da aba ${sheetName}`));
            const cols = (response.table.cols || []).map(c => (c.label || '').trim());
            const rows = (response.table.rows || []).map(r => {
              const obj = {};
              (r.c || []).forEach((cell, idx) => { obj[cols[idx] || `col_${idx}`] = cell ? (cell.f ?? cell.v ?? '') : ''; });
              return obj;
            });
            resolve(rows);
          } catch (err) { reject(err); }
        };
        const query = encodeURIComponent('select *');
        script.src = `https://docs.google.com/spreadsheets/d/${CONFIG.sheetId}/gviz/tq?sheet=${encodeURIComponent(sheetName)}&tq=${query}&tqx=responseHandler:${callbackName};out:json`;
        script.onerror = () => { cleanup(); reject(new Error(`Falha ao carregar script da aba ${sheetName}`)); };
        document.body.appendChild(script);
      });
    }

    function buildMetaMap(metaRows) {
      const map = new Map();
      metaRows.forEach(row => {
        const frota = String(row['Frota'] || '').trim();
        if (!frota) return;
        map.set(frota, { motorista: String(row['Motorista'] || '').trim(), placa: String(row['Placa'] || '').trim(), meta: parseNumber(row['Meta']) });
      });
      return map;
    }

    function normalizeMonthRows(rows) {
      return rows.map(row => {
        const equipamento = String(row['Equipamento'] || '').trim();
        if (!equipamento) return null;
        const metaInfo = state.metaMap.get(equipamento) || {};
        const supportUsage = firstNumber(row, [
          'Scania Driver Support (%)',
          'Utilização do Scania Driver Support (%)',
          'Utilizacao do Scania Driver Support (%)',
          'Uso do Scania Driver Support (%)',
          'Uso do suporte do motorista (%)',
          'Utilização do suporte do motorista (%)',
          'Utilizacao do suporte do motorista (%)'
        ]);
        const consumo = parseNumber(row['Consumo de combustível (km/l)']);
        const inercia = parseNumber(row['VeÃ­culo engrenado sem injeÃ§Ã£o de combustÃ­vel (%)']);
        const marchaLenta = parseNumber(row['Marcha lenta (%)']);
        const excessoVelocidade = parseNumber(row['Excesso de velocidade (%)']);
        const inerciaValue = parseNumber(row['Veículo engrenado sem injeção de combustível (%)']) || parseNumber(row['VeÃ­culo engrenado sem injeÃ§Ã£o de combustÃ­vel (%)']) || inercia;
        const score = computeDriverNote({
          consumo,
          meta: metaInfo.meta || 0,
          supportUsage,
          marchaLenta,
          inercia: inerciaValue,
          excessoVelocidade
        });
        return {
          equipamento,
          hodometro: parseNumber(row['Hodômetro (km)']),
          distancia: parseNumber(row['Distância (km)']),
          score,
          supportUsage,
          inercia: parseNumber(row['Veículo engrenado sem injeção de combustível (%)']),
          inercia: inerciaValue,
          marchaLenta: parseNumber(row['Marcha lenta (%)']),
          excessoVelocidade: parseNumber(row['Excesso de velocidade (%)']),
          freadasBruscas: parseNumber(row['Freadas bruscas (n°/100 km)']) || parseNumber(row['Freadas bruscas (n/100 km)']),
          consumo,
          arla32: parseNumber(row['ARLA 32 (l/km)']),
          co2: parseNumber(row['Dióxido de carbono (toneladas)']),
          mes: String(row['Mês'] || '').trim(),
          motorista: metaInfo.motorista || 'Sem cadastro',
          placa: metaInfo.placa || '-',
          meta: metaInfo.meta || 0,
          grade: gradeFromScore(score)
        };
      }).filter(Boolean);
    }

    function avg(arr, key) { return arr.length ? arr.reduce((s,i)=>s+(Number(i[key])||0),0) / arr.length : 0; }
    function sum(arr, key) { return arr.reduce((s,i)=>s+(Number(i[key])||0),0); }

    function computeMonthSummary(rows) {
      const validMetaRows = rows.filter(r => r.meta > 0);
      const metaHitRows = validMetaRows.filter(r => r.consumo >= r.meta);
      const savingsLiters = validMetaRows.reduce((acc, r) => {
        if (!r.consumo || !r.meta || r.consumo >= r.meta) return acc;
        const atual = r.distancia > 0 ? r.distancia / r.consumo : 0;
        const alvo = r.distancia > 0 ? r.distancia / r.meta : 0;
        return acc + Math.max(0, atual - alvo);
      }, 0);
      const criticalRows = rows.filter(r => r.score < 60 || (r.meta > 0 && r.consumo < r.meta));
      return {
        frota: rows.length,
        consumoMedio: avg(rows, 'consumo'),
        distanciaMedia: avg(rows, 'distancia'),
        totalKm: sum(rows, 'distancia'),
        co2Total: sum(rows, 'co2'),
        scoreMedio: avg(rows, 'score'),
        supportUsageMedio: avg(rows, 'supportUsage'),
        metaMedia: avg(validMetaRows, 'meta'),
        metaHitPct: validMetaRows.length ? (metaHitRows.length / validMetaRows.length) * 100 : 0,
        metaHitCount: metaHitRows.length,
        validMetaCount: validMetaRows.length,
        savingsLiters,
        savingsValue: savingsLiters * 6,
        criticalCount: criticalRows.length,
        criticalPct: rows.length ? (criticalRows.length / rows.length) * 100 : 0,
        grade: gradeFromScore(avg(rows, 'score')),
        marchaLenta: avg(rows, 'marchaLenta'),
        inercia: avg(rows, 'inercia'),
        excessoVelocidade: avg(rows, 'excessoVelocidade'),
        freadasBruscas: avg(rows, 'freadasBruscas')
      };
    }

    function buildInsights(current, previous, prevMonth) {
      const items = [];
      if (!current.frota) return [{ icon:'ℹ️', text:'Sem dados no filtro atual para gerar insights operacionais.' }];
      items.push({
        icon: current.metaHitPct >= 70 ? '🎯' : '📉',
        text: current.metaHitPct >= 70
          ? `${formatNumber(current.metaHitPct, 1)}% da frota filtrada atingiu a meta de consumo.`
          : `Apenas ${formatNumber(current.metaHitPct, 1)}% da frota filtrada atingiu a meta. Priorize acompanhamento.`
      });
      if (current.criticalCount > 0) {
        items.push({ icon:'🚨', text:`${formatInt(current.criticalCount)} equipamento(s) estão em condição crítica por nota baixa ou consumo abaixo da meta.` });
      }
      items.push({
        icon: current.savingsLiters > 0 ? '💰' : '✅',
        text: current.savingsLiters > 0
          ? `Potencial estimado de economia de ${formatInt(current.savingsLiters)} litros no período (≈ R$ ${formatMoney(current.savingsValue)}).`
          : 'No filtro atual, a frota está alinhada com a meta de consumo e sem potencial relevante de economia.'
      });
      if (prevMonth && previous.frota > 0) {
        const scoreDiff = current.scoreMedio - previous.scoreMedio;
        const consumoDiff = current.consumoMedio - previous.consumoMedio;
        items.push({
          icon: scoreDiff >= 0 ? '📈' : '📊',
          text: `Vs ${prevMonth}, a nota ${scoreDiff >= 0 ? 'subiu' : 'caiu'} ${formatNumber(Math.abs(scoreDiff),1)} pts e o consumo ${consumoDiff >= 0 ? 'melhorou' : 'reduziu'} ${formatNumber(Math.abs(consumoDiff),2)} km/l.`
        });
      }
      return items.slice(0,4);
    }

    function getMonthsWithData() { return CONFIG.monthNames.filter(m => (state.monthData[m] || []).length > 0); }
    function previousLoadedMonth(month) { const loaded = getMonthsWithData(); const idx = loaded.indexOf(month); return idx > 0 ? loaded[idx-1] : null; }
    function getFilteredRows(month = state.selectedMonth) {
      const rows = state.monthData[month] || [];
      if (state.selectedDriver === 'TODOS') return rows;
      return rows.filter(r => r.motorista === state.selectedDriver);
    }

    function monthlyTrend() {
      return CONFIG.monthNames.map(month => {
        const rows = state.selectedDriver === 'TODOS' ? (state.monthData[month] || []) : (state.monthData[month] || []).filter(r => r.motorista === state.selectedDriver);
        const s = computeMonthSummary(rows);
        return { month, consumo: s.consumoMedio, meta: s.metaMedia, score: s.scoreMedio, frota: s.frota };
      });
    }

    function deltaInfo(current, previous, betterWhenHigher = true, unit = '', digits = 1) {
      if (previous == null || !Number.isFinite(previous) || previous === 0 && current === 0) return { text:'— vs mês anterior', cls:'flat' };
      const diff = current - previous;
      if (Math.abs(diff) < 0.0001) return { text:'Estável vs mês anterior', cls:'flat' };
      const up = diff > 0;
      const good = betterWhenHigher ? up : !up;
      const arrow = up ? '▲' : '▼';
      return { text: `${arrow} ${formatNumber(Math.abs(diff), digits)}${unit} vs mês anterior`, cls: `${up ? 'up' : 'down'} ${good ? 'good' : 'bad'}` };
    }

    function setDelta(elId, current, previous, betterWhenHigher = true, unit = '', digits = 1) {
      const info = deltaInfo(current, previous, betterWhenHigher, unit, digits);
      const el = document.getElementById(elId);
      el.className = `delta ${info.cls}`;
      el.textContent = info.text;
    }

    function populateMonthSelect() {
      const select = document.getElementById('monthSelect');
      const withData = getMonthsWithData();
      select.innerHTML = CONFIG.monthNames.map(month => `<option value="${month}" ${!withData.includes(month) ? 'disabled' : ''}>${month}${withData.includes(month) ? '' : ' • sem dados'}</option>`).join('');
      const preferred = withData.length ? withData[withData.length - 1] : 'Janeiro';
      state.selectedMonth = withData.includes(state.selectedMonth) ? state.selectedMonth : preferred;
      select.value = state.selectedMonth;
      select.onchange = e => { state.selectedMonth = e.target.value; renderDashboard(); };
      renderAvailableMonths();
    }

    function populateDriverSelect() {
      const drivers = new Set(['TODOS']);
      getMonthsWithData().forEach(month => (state.monthData[month] || []).forEach(r => drivers.add(r.motorista)));
      const select = document.getElementById('driverSelect');
      const all = Array.from(drivers).filter(Boolean);
      select.innerHTML = all.map(name => `<option value="${name}">${name === 'TODOS' ? 'Todos os motoristas' : name}</option>`).join('');
      if (!all.includes(state.selectedDriver)) state.selectedDriver = 'TODOS';
      select.value = state.selectedDriver;
      select.onchange = e => { state.selectedDriver = e.target.value; renderDashboard(); };
    }

    function renderAvailableMonths() {
      const target = document.getElementById('availableMonths');
      const months = getMonthsWithData();
      target.innerHTML = months.map(month => `<button class="month-chip ${month === state.selectedMonth ? 'active' : ''}" data-month="${month}">${month}</button>`).join('');
      target.querySelectorAll('[data-month]').forEach(btn => btn.addEventListener('click', () => { state.selectedMonth = btn.dataset.month; document.getElementById('monthSelect').value = state.selectedMonth; renderDashboard(); }));
    }

    function renderSummary(month) {
      const rows = getFilteredRows(month);
      const prevMonth = previousLoadedMonth(month);
      const prevRows = prevMonth ? getFilteredRows(prevMonth) : [];
      const s = computeMonthSummary(rows);
      const p = computeMonthSummary(prevRows);
      document.getElementById('kpiFrota').textContent = formatInt(s.frota);
      document.getElementById('kpiConsumo').textContent = formatNumber(s.consumoMedio, 2);
      document.getElementById('kpiDistancia').textContent = formatInt(s.distanciaMedia);
      document.getElementById('kpiKmTotal').textContent = formatInt(s.totalKm);
      document.getElementById('kpiCo2').textContent = formatNumber(s.co2Total, 1);
      document.getElementById('scoreNumber').textContent = formatNumber(s.scoreMedio, 1);
      document.getElementById('scoreLetter').textContent = s.grade;
      document.getElementById('scoreLetter').className = `score-letter ${gradeClass(s.grade)}`;
      document.getElementById('realValue').textContent = `${formatNumber(s.consumoMedio, 2)} km/l`;
      document.getElementById('metaValue').textContent = s.metaMedia ? `${formatNumber(s.metaMedia, 2)} km/l` : 'Sem meta';
      const perf = s.metaMedia > 0 ? (s.consumoMedio / s.metaMedia) * 100 : 0;
      document.getElementById('metaFill').style.width = `${Math.max(0, Math.min(perf, 100))}%`;
      document.getElementById('metaText').textContent = s.metaMedia > 0 ? `${perf >= 100 ? 'Meta atingida' : 'Abaixo da meta'} (${formatNumber(perf, 1)}%) • Suporte do motorista ${formatNumber(s.supportUsageMedio,1)}%` : `Sem meta cadastrada para comparação • Suporte do motorista ${formatNumber(s.supportUsageMedio,1)}%`;
      document.getElementById('indMarcha').textContent = `${formatNumber(s.marchaLenta, 1)}%`;
      document.getElementById('indInercia').textContent = `${formatNumber(s.inercia, 1)}%`;
      document.getElementById('indExcesso').textContent = `${formatNumber(s.excessoVelocidade, 1)}%`;
      document.getElementById('indSupport').textContent = `${formatNumber(s.supportUsageMedio, 1)}%`;
      setDelta('deltaFrota', s.frota, p.frota, true, '', 0);
      setDelta('deltaConsumo', s.consumoMedio, p.consumoMedio, true, ' km/l', 2);
      setDelta('deltaDistancia', s.distanciaMedia, p.distanciaMedia, true, ' km', 0);
      setDelta('deltaKmTotal', s.totalKm, p.totalKm, true, ' km', 0);
      setDelta('deltaCo2', s.co2Total, p.co2Total, false, ' t', 1);
      setDelta('deltaScore', s.scoreMedio, p.scoreMedio, true, ' pts', 1);
      setDelta('deltaMarcha', s.marchaLenta, p.marchaLenta, false, ' p.p.', 1);
      setDelta('deltaInercia', s.inercia, p.inercia, true, ' p.p.', 1);
      setDelta('deltaExcesso', s.excessoVelocidade, p.excessoVelocidade, false, ' p.p.', 1);
      setDelta('deltaSupport', s.supportUsageMedio, p.supportUsageMedio, true, ' p.p.', 1);
      document.getElementById('metaHitPct').textContent = `${formatNumber(s.metaHitPct,1)}%`;
      document.getElementById('metaHitCount').textContent = `${formatInt(s.metaHitCount)} de ${formatInt(s.validMetaCount || s.frota)} equip.`;
      document.getElementById('savingsLiters').textContent = formatInt(s.savingsLiters);
      document.getElementById('savingsValueFoot').textContent = `Estimativa financeira: R$ ${formatMoney(s.savingsValue)}`;
      document.getElementById('criticalCount').textContent = formatInt(s.criticalCount);
      document.getElementById('criticalPct').textContent = `${formatNumber(s.criticalPct,1)}% da frota`;
      setDelta('deltaMetaHit', s.metaHitPct, p.metaHitPct, true, ' p.p.', 1);
      setDelta('deltaSavings', s.savingsLiters, p.savingsLiters, false, ' l', 0);
      setDelta('deltaCritical', s.criticalCount, p.criticalCount, false, '', 0);
      renderComparePanel(month, s, p, prevMonth);
      renderInsightsPanel(s, p, prevMonth);
    }

    function renderComparePanel(month, current, previous, prevMonth) {
      document.getElementById('compareMonthLabel').textContent = prevMonth ? `${month} x ${prevMonth}` : 'Sem mês anterior disponível';
      const target = document.getElementById('compareStats');
      if (!prevMonth || previous.frota === 0) { target.innerHTML = '<div class="empty">Sem base comparativa para o mês selecionado.</div>'; return; }
      const stats = [
        ['Consumo médio', current.consumoMedio, previous.consumoMedio, true, ' km/l', 2],
        ['Nota média', current.scoreMedio, previous.scoreMedio, true, ' pts', 1],
        ['Suporte do motorista', current.supportUsageMedio, previous.supportUsageMedio, true, ' %', 1],
        ['Marcha lenta', current.marchaLenta, previous.marchaLenta, false, ' p.p.', 1],
        ['Excesso de velocidade', current.excessoVelocidade, previous.excessoVelocidade, false, ' p.p.', 1],
        ['Km total rodado', current.totalKm, previous.totalKm, true, ' km', 0],
        ['CO₂ total', current.co2Total, previous.co2Total, false, ' t', 1],
      ];
      target.innerHTML = stats.map(([label, a, b, better, unit, digits]) => {
        const d = deltaInfo(a, b, better, unit, digits);
        return `<div class="compare-stat"><div><strong>${label}</strong><div class="subtle">Atual: ${formatNumber(a, digits)}${unit} • Anterior: ${formatNumber(b, digits)}${unit}</div></div><div class="delta ${d.cls}">${d.text}</div></div>`;
      }).join('');
    }

    function renderInsightsPanel(current, previous, prevMonth) {
      const target = document.getElementById('insightsList');
      const insights = buildInsights(current, previous, prevMonth);
      target.innerHTML = insights.map(item => `<div class="insight-item"><div class="insight-icon">${item.icon}</div><div>${item.text}</div></div>`).join('');
    }

    function renderTrendChart() {
      const data = monthlyTrend().filter(item => item.frota > 0);
      const options = {
        chart: { type: 'line', height: 320, toolbar: { show: false }, zoom: { enabled: false } },
        series: [{ name: 'Consumo médio', data: data.map(x => Number(x.consumo.toFixed(2))) }, { name: 'Meta média', data: data.map(x => Number((x.meta || 0).toFixed(2))) }, { name: 'Nota média', data: data.map(x => Number(x.score.toFixed(1))) }],
        stroke: { curve: 'smooth', width: [4, 2, 3], dashArray: [0, 6, 0] },
        colors: ['#2563eb', '#16a34a', '#d71920'],
        xaxis: { categories: data.map(x => x.month.slice(0,3)) },
        yaxis: [{ title: { text: 'km/l' } }, { opposite: true, title: { text: 'Nota' } }],
        dataLabels: { enabled: false },
        legend: { position: 'top' },
        grid: { borderColor: '#e5e7eb' },
        tooltip: { shared: true }
      };
      if (state.charts.trend) state.charts.trend.destroy();
      state.charts.trend = new ApexCharts(document.querySelector('#chartTrend'), options);
      state.charts.trend.render();
    }

    function renderRankingChart(month) {
      const fleetRows = [...(state.monthData[month] || [])];
      const bestRows = fleetRows.slice().sort((a,b)=> b.consumo - a.consumo).slice(0,10).reverse();
      const worstRows = fleetRows.slice().sort((a,b)=> a.consumo - b.consumo).slice(0,10).reverse();
      const commonOpts = {
        chart: { type: 'bar', height: 260, toolbar: { show: false } },
        colors: ['#38bdf8'],
        plotOptions: { bar: { horizontal: true, borderRadius: 8, barHeight: '72%' } },
        dataLabels: { enabled: false },
        grid: { borderColor: '#e5e7eb' }
      };
      if (state.charts.ranking) state.charts.ranking.destroy();
      state.charts.ranking = new ApexCharts(document.querySelector('#chartRanking'), {
        ...commonOpts,
        series: [{ name: 'Consumo', data: bestRows.map(r => Number(r.consumo.toFixed(2))) }],
        xaxis: { categories: bestRows.map(r => `#${r.equipamento}`) },
        tooltip: {
          y: { formatter: v => `${formatNumber(v,2)} km/l` },
          custom: ({ dataPointIndex }) => {
            const row = bestRows[dataPointIndex];
            if (!row) return '';
            return `<div style="padding:10px 12px;min-width:210px"><strong>Equip. #${row.equipamento}</strong><br><span style="color:#475569">${row.motorista || '-'} • ${row.placa || '-'}</span><br><span style="color:#0f172a">Consumo: <strong>${formatNumber(row.consumo,2)} km/l</strong></span></div>`;
          }
        }
      });
      state.charts.ranking.render();
      if (state.charts.worstRanking) state.charts.worstRanking.destroy();
      state.charts.worstRanking = new ApexCharts(document.querySelector('#chartWorstRanking'), {
        ...commonOpts,
        colors: ['#fb7185'],
        series: [{ name: 'Consumo', data: worstRows.map(r => Number(r.consumo.toFixed(2))) }],
        xaxis: { categories: worstRows.map(r => `#${r.equipamento}`) },
        tooltip: {
          y: { formatter: v => `${formatNumber(v,2)} km/l` },
          custom: ({ dataPointIndex }) => {
            const row = worstRows[dataPointIndex];
            if (!row) return '';
            return `<div style="padding:10px 12px;min-width:210px"><strong>Equip. #${row.equipamento}</strong><br><span style="color:#475569">${row.motorista || '-'} • ${row.placa || '-'}</span><br><span style="color:#0f172a">Consumo: <strong>${formatNumber(row.consumo,2)} km/l</strong></span></div>`;
          }
        }
      });
      state.charts.worstRanking.render();
      document.getElementById('rankingSubtitle').textContent = `Frota completa de ${month} • filtro por motorista não aplicado`;
      document.getElementById('worstRankingSubtitle').textContent = `Frota completa de ${month} • foco para ação imediata`;
    }

    function renderGradeDistribution(month) {
      const rows = state.monthData[month] || [];
      const counts = ['A','B','C','D','E'].map(g => rows.filter(r => r.grade === g).length);
      if (state.charts.gradeDist) state.charts.gradeDist.destroy();
      state.charts.gradeDist = new ApexCharts(document.querySelector('#chartGradeDist'), {
        chart: { type: 'bar', height: 250, toolbar: { show: false } },
        series: [{ name: 'Equipamentos', data: counts }],
        xaxis: { categories: ['A','B','C','D','E'] },
        colors: ['#22c55e','#84cc16','#eab308','#f97316','#ef4444'],
        plotOptions: { bar: { borderRadius: 10, distributed: true, columnWidth: '52%' } },
        dataLabels: { enabled: true },
        legend: { show: false },
        grid: { borderColor: '#e5e7eb' },
        yaxis: { title: { text: 'Quantidade' } }
      });
      state.charts.gradeDist.render();
      const subtitle = document.getElementById('gradeDistSubtitle');
      if (subtitle) subtitle.textContent = `Frota completa de ${month}`;
    }

    function computeTrainingList(month) {
      const rows = state.monthData[month] || [];
      const byDriver = new Map();
      rows.forEach(r => {
        if (!byDriver.has(r.motorista)) byDriver.set(r.motorista, []);
        byDriver.get(r.motorista).push(r);
      });
      return Array.from(byDriver.entries()).map(([motorista, items]) => {
        const s = computeMonthSummary(items);
        const severity = (s.scoreMedio < 60 ? 2 : 0) + (s.metaMedia > 0 && s.consumoMedio < s.metaMedia ? 1 : 0) + (s.supportUsageMedio < 60 ? 1 : 0) + (s.marchaLenta > 20 ? 1 : 0) + (s.excessoVelocidade > 5 ? 1 : 0);
        return {
          motorista,
          equipamentos: items.map(i => i.equipamento).join(', '),
          score: s.scoreMedio,
          supportUsage: s.supportUsageMedio,
          consumo: s.consumoMedio,
          meta: s.metaMedia,
          severity,
          label: severity >= 3 ? 'treinamento alto' : severity >= 2 ? 'atenção média' : 'monitorar',
          cls: severity >= 3 ? 'lvl-high' : severity >= 2 ? 'lvl-med' : 'lvl-low'
        };
      }).sort((a,b) => b.severity - a.severity || a.score - b.score).slice(0,6);
    }

    function renderTrainingList(month) {
      const list = computeTrainingList(month);
      const target = document.getElementById('trainingList');
      if (!list.length) { target.innerHTML = '<div class="empty">Sem dados suficientes para recomendar treinamento.</div>'; return; }
      target.innerHTML = list.map(item => `
        <div class="list-item">
          <div>
            <strong>${item.motorista}</strong>
            <span class="list-sub">Frotas: ${item.equipamentos} • Nota ${formatNumber(item.score,1)} • Suporte ${formatNumber(item.supportUsage,1)}% • Consumo ${formatNumber(item.consumo,2)} km/l${item.meta ? ` • Meta ${formatNumber(item.meta,2)}` : ''}</span>
          </div>
          <span class="training-level ${item.cls}">${item.label}</span>
        </div>`).join('');
    }

    function computeDriverRanking(month) {
      const rows = state.monthData[month] || [];
      const map = new Map();
      rows.forEach(r => {
        if (!map.has(r.motorista)) map.set(r.motorista, []);
        map.get(r.motorista).push(r);
      });
      return Array.from(map.entries()).map(([motorista, items]) => {
        const s = computeMonthSummary(items);
        const health = s.scoreMedio;
        return { motorista, score: s.scoreMedio, supportUsage: s.supportUsageMedio, consumo: s.consumoMedio, meta: s.metaMedia, health };
      }).sort((a,b) => b.health - a.health);
    }

    function renderDriverSummaryTargets(month, targets) {
      const rows = getFilteredRows(month);
      if (state.selectedDriver === 'TODOS') {
        const ranking = computeDriverRanking(month);
        const titleText = 'Visão executiva de condutores';
        const emptyHtml = '<div class="empty">Sem dados de motoristas para este período.</div>';
        const best = ranking.slice(0,5);
        const worst = ranking.slice(-5).reverse();
        const html = ranking.length ? `
          <div class="summary-panel">
              <div class="summary-box tall"><div class="subtle">Top motoristas do mês</div><div class="list">${best.map(r => `<div class="list-item"><div><strong>${r.motorista}</strong><span class="list-sub">Nota ${formatNumber(r.score,1)} • Suporte ${formatNumber(r.supportUsage,1)}% • Consumo ${formatNumber(r.consumo,2)} km/l${r.meta ? ` • Meta ${formatNumber(r.meta,2)}` : ''}</span></div><span class="training-level lvl-low">destaque</span></div>`).join('')}</div></div>
              <div class="summary-box tall"><div class="subtle">Condutores para ação imediata</div><div class="list">${worst.map(r => `<div class="list-item"><div><strong>${r.motorista}</strong><span class="list-sub">Nota ${formatNumber(r.score,1)} • Suporte ${formatNumber(r.supportUsage,1)}% • Consumo ${formatNumber(r.consumo,2)} km/l${r.meta ? ` • Meta ${formatNumber(r.meta,2)}` : ''}</span></div><span class="training-level lvl-high">prioridade</span></div>`).join('')}</div></div>
          </div>` : emptyHtml;
        targets.forEach(([titleId, boxId]) => {
          const title = document.getElementById(titleId);
          const box = document.getElementById(boxId);
          if (!title || !box) return;
          title.textContent = titleText;
          box.innerHTML = html;
        });
        return;
      }

      const s = computeMonthSummary(rows);
      const prevMonth = previousLoadedMonth(month);
      const prevRows = prevMonth ? getFilteredRows(prevMonth) : [];
      const prevSummary = computeMonthSummary(prevRows);
      const scoreDelta = deltaInfo(s.scoreMedio, prevSummary.scoreMedio, true, ' pts', 1);
      const html = `
        <div class="summary-panel">
          <div class="summary-box"><div class="subtle">Equipamentos</div><div class="score-number">${formatInt(rows.length)}</div><div class="subtle">Frotas analisadas no mês</div></div>
          <div class="summary-box"><div class="subtle">Nota média</div><div class="score-number">${formatNumber(s.scoreMedio,1)}</div><div class="delta ${scoreDelta.cls}">${scoreDelta.text}</div></div>
          <div class="summary-box"><div class="subtle">Consumo</div><div class="score-number">${formatNumber(s.consumoMedio,2)}</div><div class="subtle">km/l ${s.metaMedia ? `• meta ${formatNumber(s.metaMedia,2)}` : ''}<br>Suporte do motorista: <strong>${formatNumber(s.supportUsageMedio,1)}%</strong></div></div>
          <div class="summary-box"><div class="subtle">Pontos de atenção</div><div class="subtle" style="margin-top:10px; line-height:1.7;">Marcha lenta: <strong>${formatNumber(s.marchaLenta,1)}%</strong><br>Inércia: <strong>${formatNumber(s.inercia,1)}%</strong><br>Excesso vel.: <strong>${formatNumber(s.excessoVelocidade,1)}%</strong></div></div>
        </div>`;
      targets.forEach(([titleId, boxId]) => {
        const title = document.getElementById(titleId);
        const box = document.getElementById(boxId);
        if (!title || !box) return;
        title.textContent = state.selectedDriver;
        box.innerHTML = html;
      });
    }

    function renderDriverSummary(month) {
      const box = document.getElementById('driverSummaryBox');
      const title = document.getElementById('driverSummaryTitle');
      const rows = getFilteredRows(month);
      if (state.selectedDriver === 'TODOS') {
        title.textContent = 'Todos os motoristas';
        box.innerHTML = '<div class="empty">Selecione um motorista no filtro para ver a análise individual e identificar necessidade de treinamento.</div>';
        return;
      }
      const s = computeMonthSummary(rows);
      title.textContent = state.selectedDriver;
      box.innerHTML = `
        <div class="summary-panel">
          <div class="summary-box"><div class="subtle">Equipamentos</div><div class="score-number">${formatInt(rows.length)}</div><div class="subtle">Frotas analisadas no mês</div></div>
          <div class="summary-box"><div class="subtle">Score médio</div><div class="score-number">${formatNumber(s.scoreMedio,1)}</div><div class="delta ${deltaInfo(s.scoreMedio, computeMonthSummary(previousLoadedMonth(month) ? getFilteredRows(previousLoadedMonth(month)) : []).scoreMedio, true, ' pts', 1).cls}">${deltaInfo(s.scoreMedio, computeMonthSummary(previousLoadedMonth(month) ? getFilteredRows(previousLoadedMonth(month)) : []).scoreMedio, true, ' pts', 1).text}</div></div>
          <div class="summary-box"><div class="subtle">Consumo</div><div class="score-number">${formatNumber(s.consumoMedio,2)}</div><div class="subtle">km/l ${s.metaMedia ? `• meta ${formatNumber(s.metaMedia,2)}` : ''}</div></div>
          <div class="summary-box"><div class="subtle">Pontos de atenção</div><div class="subtle" style="margin-top:10px; line-height:1.7;">Marcha lenta: <strong>${formatNumber(s.marchaLenta,1)}%</strong><br>Excesso vel.: <strong>${formatNumber(s.excessoVelocidade,1)}%</strong><br>Freadas: <strong>${formatNumber(s.freadasBruscas,2)}</strong></div></div>
        </div>`;
    }

    function renderDriverSummary(month) {
      renderDriverSummaryTargets(month, [
        ['driverSummaryTitle', 'driverSummaryBox'],
        ['driverSummaryTitleFleet', 'driverSummaryBoxFleet']
      ]);
    }

    function renderIdleImpactChart(month) {
      const target = document.querySelector('#chartIdleImpact');
      if (!target) return;

      const rows = getFilteredRows(month)
        .map(r => ({
          ...r,
          idleImpact: r.consumo > 0 && r.distancia > 0 ? (r.distancia / r.consumo) * (r.marchaLenta / 100) : 0
        }))
        .filter(r => r.idleImpact > 0)
        .sort((a,b) => b.idleImpact - a.idleImpact)
        .slice(0, 10)
        .reverse();

      const subtitle = document.getElementById('idleImpactSubtitle');
      if (subtitle) {
        subtitle.textContent = state.selectedDriver === 'TODOS'
          ? `Maiores impactos por equipamento em ${month}`
          : `Impacto estimado de marcha lenta para ${state.selectedDriver}`;
      }

      if (state.charts.idleImpact) state.charts.idleImpact.destroy();
      if (!rows.length) {
        target.innerHTML = '<div class="empty">Sem dados suficientes para estimar impacto de marcha lenta.</div>';
        return;
      }

      target.innerHTML = '';
      state.charts.idleImpact = new ApexCharts(target, {
        chart: { type: 'bar', height: 300, toolbar: { show: false } },
        series: [{ name: 'Litros estimados', data: rows.map(r => Number(r.idleImpact.toFixed(1))) }],
        plotOptions: { bar: { horizontal: true, borderRadius: 8, barHeight: '66%' } },
        colors: ['#8b5cf6'],
        dataLabels: { enabled: true },
        xaxis: { categories: rows.map(r => r.equipamento), title: { text: 'Litros estimados' } },
        grid: { borderColor: '#e5e7eb' },
        tooltip: {
          y: {
            formatter: (_, ctx) => {
              const item = rows[ctx.dataPointIndex];
              return `${formatNumber(item.idleImpact,1)} L • ${item.motorista} • placa ${item.placa} • ${formatNumber(item.marchaLenta,1)}%`;
            }
          }
        }
      });
      state.charts.idleImpact.render();
    }

    function setupPageLayout() {
      const footer = document.querySelector('.footer-note');
      if (!footer) return;

      const operationalPage = document.getElementById('pageOperational');
      if (operationalPage) {
        const trendCharts = operationalPage.querySelectorAll('#chartTrend');
        if (trendCharts.length > 1) {
          const extraTrendBlock = trendCharts[1].closest('.stack-grid');
          if (extraTrendBlock) extraTrendBlock.style.display = 'none';
        }
      }

      let pageFleet = document.getElementById('pageFleet');
      if (!pageFleet) {
        pageFleet = document.createElement('section');
        pageFleet.className = 'page-section';
        pageFleet.id = 'pageFleet';
        pageFleet.innerHTML = `
          <div class="page-head">
            <div>
              <span class="page-kicker">Página 3</span>
              <h2 class="page-title">Detalhamento da frota</h2>
            </div>
            <div class="page-note">Página operacional para análise, auditoria e acompanhamento por equipamento</div>
          </div>
          <div class="fleet-detail-grid" id="fleetDetailGrid">
            <div class="fleet-top-grid">
              <section class="panel soft-accent">
                <div class="panel-head">
                  <h3 class="panel-title" style="margin:0;">Maiores consumos em marcha lenta</h3>
                  <span class="subtle" id="idleImpactSubtitle">Maiores impactos por equipamento no filtro atual</span>
                </div>
                <div id="chartIdleImpact"></div>
              </section>
              <section class="panel soft-accent">
                <div class="panel-head">
                  <h3 class="panel-title" style="margin:0;">Resumo do motorista filtrado</h3>
                  <span class="subtle" id="driverSummaryTitleFleet">Todos os motoristas</span>
                </div>
                <div id="driverSummaryBoxFleet">
                  <div class="empty">Selecione um motorista para análise individual.</div>
                </div>
              </section>
            </div>
          </div>`;
        footer.parentNode.insertBefore(pageFleet, footer);
      }

      const tablePanel = document.getElementById('tableWrap')?.closest('.panel');
      const fleetGrid = document.getElementById('fleetDetailGrid');
      if (tablePanel && fleetGrid && tablePanel.parentElement !== fleetGrid) {
        tablePanel.classList.add('fleet-table-panel');
        fleetGrid.appendChild(tablePanel);
      }
    }

    function setActivePage(page) {
      state.currentPage = page;
      const pageMap = {
        executive: 'pageExecutive',
        operational: 'pageOperational',
        fleet: 'pageFleet'
      };
      Object.entries(pageMap).forEach(([key, id]) => {
        const section = document.getElementById(id);
        if (section) section.classList.toggle('active', key === page);
      });
      document.querySelectorAll('.nav-pill[data-page]').forEach(btn => {
        btn.classList.toggle('active', btn.dataset.page === page);
      });
    }

    function setupPageNav() {
      document.querySelectorAll('.nav-pill[data-page]').forEach(btn => {
        if (btn.dataset.navBound === '1') return;
        btn.dataset.navBound = '1';
        btn.addEventListener('click', () => setActivePage(btn.dataset.page));
      });
    }

    function renderTable(month) {
      const rows = [...getFilteredRows(month)].sort((a,b)=> b.consumo - a.consumo);
      document.getElementById('tableSubtitle').textContent = state.selectedDriver === 'TODOS' ? `Todos os motoristas • ${rows.length} linha(s)` : `${state.selectedDriver} • ${rows.length} linha(s)`;
      const prevMonth = previousLoadedMonth(month);
      const prevRows = prevMonth ? (state.selectedDriver === 'TODOS' ? (state.monthData[prevMonth] || []) : (state.monthData[prevMonth] || []).filter(r => r.motorista === state.selectedDriver)) : [];
      const prevMap = new Map(prevRows.map(r => [r.equipamento + '|' + r.motorista, r]));
      const target = document.getElementById('tableWrap');
      if (!rows.length) { target.innerHTML = '<div class="empty">Nenhum dado encontrado para este filtro.</div>'; return; }
      target.innerHTML = `
        <table>
          <thead>
            <tr>
              <th>Equipamento</th><th>Placa</th><th>Motorista</th><th>Meta</th><th>Consumo</th><th>Δ Consumo</th><th>Suporte</th><th>Nota</th><th>Δ Nota</th><th>Faixa</th><th>Distância</th><th>Marcha lenta</th><th>Inércia</th><th>Excesso vel.</th><th>Freadas</th><th>CO₂</th>
            </tr>
          </thead>
          <tbody>
            ${rows.map(r => {
              const prev = prevMap.get(r.equipamento + '|' + r.motorista);
              const dCons = deltaInfo(r.consumo, prev?.consumo, true, '', 2);
              const dScore = deltaInfo(r.score, prev?.score, true, '', 1);
              return `<tr>
                <td><strong>${r.equipamento}</strong></td>
                <td>${r.placa}</td>
                <td>${r.motorista}</td>
                <td>${r.meta ? formatNumber(r.meta,1) : '-'}</td>
                <td><strong>${formatNumber(r.consumo,2)}</strong></td>
                <td><span class="delta ${dCons.cls}">${dCons.text.replace(' vs mês anterior','')}</span></td>
                <td>${formatNumber(r.supportUsage,1)}%</td>
                <td>${formatNumber(r.score,1)}</td>
                <td><span class="delta ${dScore.cls}">${dScore.text.replace(' vs mês anterior','')}</span></td>
                <td><span class="pill" style="background:${pillColor(r.grade)}">${r.grade}</span></td>
                <td>${formatInt(r.distancia)}</td>
                <td>${formatNumber(r.marchaLenta,1)}%</td>
                <td>${formatNumber(r.inercia,1)}%</td>
                <td>${formatNumber(r.excessoVelocidade,1)}%</td>
                <td>${formatNumber(r.freadasBruscas,2)}</td>
                <td>${formatNumber(r.co2,1)}</td>
              </tr>`;
            }).join('')}
          </tbody>
        </table>`;
    }

    function renderDashboard() {
      renderAvailableMonths();
      renderSummary(state.selectedMonth);
      renderTrendChart();
      renderRankingChart(state.selectedMonth);
      renderGradeDistribution(state.selectedMonth);
      renderTrainingList(state.selectedMonth);
      renderDriverSummary(state.selectedMonth);
      renderIdleImpactChart(state.selectedMonth);
      renderTable(state.selectedMonth);
      setActivePage(state.currentPage);
      const loadedCount = getMonthsWithData().length;
      document.getElementById('lastUpdateBadge').textContent = `Período: ${state.selectedMonth} • ${loadedCount} mês(es) com dados • Filtro: ${state.selectedDriver === 'TODOS' ? 'Todos' : state.selectedDriver}`;
    }

    async function init() {
      try {
        document.getElementById('lastUpdateBadge').textContent = 'Carregando base...';
        const metaRows = await loadSheetJSONP(CONFIG.metaSheetName);
        state.metaRows = metaRows;
        state.metaMap = buildMetaMap(metaRows);
        const monthResults = await Promise.all(CONFIG.monthNames.map(async month => {
          try { return [month, normalizeMonthRows(await loadSheetJSONP(month))]; }
          catch (err) { console.warn(`Falha ao carregar ${month}`, err); return [month, []]; }
        }));
        state.monthData = Object.fromEntries(monthResults);
        setupPageLayout();
        setupPageNav();
        populateMonthSelect();
        populateDriverSelect();
        renderDashboard();
      } catch (error) {
        console.error(error);
        document.getElementById('tableWrap').innerHTML = `<div class="empty">Erro ao carregar os dados: ${error.message}</div>`;
        document.getElementById('lastUpdateBadge').textContent = 'Falha ao carregar a base';
      }
    }

    document.getElementById('refreshBtn').addEventListener('click', init);
    document.getElementById('pdfBtn').addEventListener('click', () => window.print());
    window.addEventListener('load', () => {
      setupPageLayout();
      setupPageNav();
      init();
    });
  
